interface Allocation {
  token: string;
  weight: number;
  value: number;
  color: string;
}

interface AllocationChartProps {
  allocations: Allocation[];
}

export function AllocationChart({ allocations }: AllocationChartProps) {
  const total = allocations.reduce((sum, a) => sum + a.value, 0);

  return (
    <div className="space-y-4">
      {/* Bar visualization */}
      <div className="flex h-8 rounded-lg overflow-hidden gap-0.5">
        {allocations.map((a, i) => (
          <div
            key={a.token}
            className="transition-all duration-500 hover:opacity-80"
            style={{
              width: `${a.weight * 100}%`,
              backgroundColor: a.color,
            }}
            title={`${a.token}: ${(a.weight * 100).toFixed(0)}%`}
          />
        ))}
      </div>

      {/* Legend */}
      <div className="grid grid-cols-3 gap-4">
        {allocations.map((a) => (
          <div key={a.token} className="flex items-center gap-3">
            <div
              className="w-3 h-3 rounded-full"
              style={{ backgroundColor: a.color }}
            />
            <div>
              <p className="text-sm font-medium">{a.token}</p>
              <p className="text-xs text-[#6b7280]">
                ${(a.value).toLocaleString()} · {(a.weight * 100).toFixed(0)}%
              </p>
            </div>
          </div>
        ))}
      </div>

      {/* Regime Profile Note */}
      <div className="mt-4 p-3 bg-[#1a1a2a] rounded-lg border border-[#1e1e2e]">
        <p className="text-xs text-[#6b7280]">
          <span className="text-green-500 font-medium">BULL_TRENDING</span> profile active — 
          60% risk assets for growth, 20% USYC yield, 20% USDC dry powder. 
          Agent will rebalance if regime shifts below 60% confidence.
        </p>
      </div>
    </div>
  );
}
