const REGIME_COLORS: Record<string, string> = {
  BULL_TRENDING: "from-green-500 to-emerald-600",
  BEAR_TRENDING: "from-red-500 to-rose-600",
  RANGE_BOUND: "from-blue-500 to-indigo-600",
  HIGH_VOLATILITY: "from-orange-500 to-amber-600",
  ACCUMULATION: "from-purple-500 to-violet-600",
  PRICE_DISCOVERY: "from-cyan-500 to-teal-600",
};

const REGIME_DESCRIPTIONS: Record<string, string> = {
  BULL_TRENDING: "Growth mode — ride the trend with trailing stops",
  BEAR_TRENDING: "Defense mode — preserve capital, earn yield",
  RANGE_BOUND: "Accumulation mode — farm yield, wait for direction",
  HIGH_VOLATILITY: "Risk-off — minimize exposure, wait for clarity",
  ACCUMULATION: "DCA mode — systematic accumulation at lower prices",
  PRICE_DISCOVERY: "Exploration — small positions, wide stops",
};

interface RegimeBadgeProps {
  regime: string;
  confidence: number;
}

export function RegimeBadge({ regime, confidence }: RegimeBadgeProps) {
  const gradient = REGIME_COLORS[regime] || REGIME_COLORS["RANGE_BOUND"];
  const description = REGIME_DESCRIPTIONS[regime] || "";
  const displayName = regime.replace(/_/g, " ");

  return (
    <div>
      <div className={`inline-flex items-center gap-2 px-4 py-2 rounded-xl bg-gradient-to-r ${gradient} text-white font-bold text-lg shadow-lg`}>
        <span className="w-2 h-2 rounded-full bg-white/80 animate-pulse" />
        {displayName}
      </div>
      <div className="mt-3">
        <div className="flex items-center justify-between mb-1">
          <span className="text-xs text-[#6b7280]">Confidence</span>
          <span className="text-xs font-medium">{confidence}%</span>
        </div>
        <div className="w-full h-2 bg-[#1e1e2e] rounded-full overflow-hidden">
          <div
            className={`h-full rounded-full bg-gradient-to-r ${gradient} transition-all duration-500`}
            style={{ width: `${confidence}%` }}
          />
        </div>
      </div>
      <p className="text-sm text-[#9ca3af] mt-3 leading-relaxed">{description}</p>
    </div>
  );
}
