interface StatusCardProps {
  status: string;
  uptime: string;
}

export function StatusCard({ status, uptime }: StatusCardProps) {
  const isActive = status === "active";

  return (
    <div className={`flex items-center gap-2 px-4 py-2 rounded-full border ${
      isActive
        ? "border-green-500/30 bg-green-500/10 status-active"
        : "border-red-500/30 bg-red-500/10"
    }`}>
      <span className={`w-2 h-2 rounded-full ${isActive ? "bg-green-500" : "bg-red-500"}`} />
      <span className="text-sm font-medium">{isActive ? "Agent Active" : "Agent Offline"}</span>
      {isActive && (
        <span className="text-xs text-[#6b7280]">· {uptime}</span>
      )}
    </div>
  );
}
